#include<bits/stdc++.h>
using namespace std;
bitset<3010> a[3010];
int main()
{
	int n,m;
	scanf("%d%d",&n,&m);
	char ch=getchar();
	for(int i=1;i<=m;i++)
	{
		for(int j=1;j<=n+1;j++)
		{
			while(!isdigit(ch))
			{
				ch=getchar();
			}
			a[i][j]=(bool)(ch=='1');
			ch=getchar();
		}
	}
	int ans=0;
	for(int i=1;i<=n;i++)
	{
		int j=i;
		for(;j<=m;j++)
		{
			if(a[j][i]==1)
			{
				break;
			}
		}
		if(j>m)
		{
			printf("Cannot Determine");
			return 0;
		}
		ans=max(ans,j);
		if(j!=i)
		{
			swap(a[j],a[i]);
		}
		for(int k=1;k<=m;k++)if(i!=k&&a[k][i])
		{
			a[k]^=a[i];
		}
	}
	printf("%d\n",ans);
	for(int i=1;i<=n;i++)
	{
		if(a[i][n+1])
		{
			printf("?y7M#\n");
		}
		else
		{
			printf("Earth\n");
		}
	}
	return 0;
}
